You have a ReferenceError because you didn't install the 'ethers' package. You can fix it by installing the package using npm, like this:

```sh
npm install ethers
```

Now add this line at the beginning of your `1_deploy_contracts.js` file, right after declaring the `LoanNFT` variable:

```js
const ethers = require('ethers');
```

So, your `1_deploy_contracts.js` file should look like:

```js
const LoanNFT = artifacts.require("LoanNFT");
const ethers = require('ethers');

(async () => {
  const name = "LoanNFT";
  const symbol = "LNFT";
  const couponRate = 5;
  const mintingPrice = web3.utils.toWei("0.001", "ether");

  const loanNFTInstance = await LoanNFT.new(name, symbol, couponRate, mintingPrice);
  console.log("Deployed LoanNFT:", loanNFTInstance.address);
})();

module.exports = function (deployer) {
  deployer.deploy(LoanNFT, "LoanNFT", "LNFT", 2, ethers.utils.parseEther("0.001"));
};
```

